if (initialized) {
	webView.dispose();
}

var webView: StageWebView = new StageWebView();
var initialized = false;

function stageWebViewGif(isi) {
	webView.stage = this.stage;
	if (webView.viewPort) {
		webView.viewPort = null;
	}
	if (!initialized) {
		initialized = true;
	}
	webView.viewPort = new Rectangle(120, 300, 480, 340);

	var gif: String = isi;

	webView.loadURL(gif);
}

webView.stage = null;
webView.viewPort = null;

stop();

